import { Fragment, useState } from 'react';
import { Modal as BModal } from 'react-bootstrap';
import Carousel from 'react-bootstrap/Carousel';
import { gallery } from '../Gallery';
import '../App.css';

const Modal = () => {
    const [show, setShow] = useState(false);
    const [data, setData] = useState({title: '', slides: [], description: '', iSelected: 0});
    const [index, setIndex] = useState(0);

  const handleSelect = (selectedIndex:number, e:any) => {
    setIndex(selectedIndex);
  };
    
    const elements:any = [
        `${process.env.PUBLIC_URL}/assets/images/Shopify/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/justChat/2.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/SocialNetwork/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/SistemaVotacion/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/HR_Managment/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/MERN_Stack/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/ProcesadorTransacciones/1.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/ContactApp/2.PNG`,
        `${process.env.PUBLIC_URL}/assets/images/MemoryGame/2.PNG`,
    ];
    
    const handleShow = (data:any) => {
        //console.log(data);
        setData(data);
        setShow(true);
    }

    const handleClose = () => {
        setShow(false);
        setData({title: '', slides: [], description: '', iSelected: 0});
    }

    return (
        <Fragment>
        {
            gallery.images.map((partitions:any, idx:number) => (
                <div key={idx} className="mt-5 col-12 col-sm-12 col-md-4">
                <img
                    className="item-image shadow-lg zoom"
                    src={elements[idx]}
                    alt={"image"+(idx)}
                    onClick={() => handleShow({
                        title: gallery.titles[idx],
                        slides: partitions,
                        description: gallery.descriptions[idx],
                        iSelected: idx
                    })}
                />
                </div>
            ))
        }
        <BModal
            show={show}
            onHide={() => handleClose()}
            size="lg"
        >
            <div className="container my-2 d-flex justify-content-end pr-5">
                <div className="closeBtn float-right text-muted h5"
                    onClick={() => handleClose()}>✕</div>
            </div>
            <BModal.Title className="text-center text-muted font-weight-bold">
                { data?.title }
            </BModal.Title>
            <hr />
            <div className="container d-flex justify-content-center">
            <Carousel fade={true} activeIndex={index} onSelect={handleSelect} className="shadow mx-5">
                {
                    data?.slides?.map((link:string, idx:number) => (
                        <Carousel.Item key={idx} >
                            <img
                                src={link}
                                alt={"image_"+link}
                                className="d-block w-100"
                            />
                        </Carousel.Item>
                    ))
                }
            </Carousel>
            </div>
            <BModal.Body>
                <div className="mx-auto container px-5 text-center">
                        <p>{data?.description}</p>
                </div>
            </BModal.Body>
            <hr />
            <div className="mb-5 d-flex justify-content-center align-items-center">
                {
                    gallery?.techs[data.iSelected]?.map((tech:any, idx:number) => (
                        <a className="px-2">
                            <img
                                src={tech}
                                width="40px"
                                height="40px"
                            />
                        </a>
                    ))
                }
            </div>
        </BModal>
        </Fragment>
    );
}

export default Modal;