import { Fragment } from 'react';

const Banner = () => {
    const BannerStyles: any = {
        boxShadow: '0px 8px 8px -6px rgba(0,0,0,.5)'
    }

    return (
        <Fragment>
            <div className="d-flex justify-content-end align-items-end">
                <a href="#home" className="text-white scrollToTop"><i className="fas fa-angle-up rounded-circle homeBtn"
                        style={BannerStyles}></i></a>
            </div>
            <div id="home" className="navbar header">
                <div id="head" className="mx-auto container text-white font-big d-flex justify-content-center">
                    <div className="container text-center">
                        <p>Jacsel Guridi Diaz</p>
                        <hr/>
                        <p className="h5 text-light title">Software Developer</p>
                    </div>
                </div>
            </div>
        </Fragment>
    );
}

export default Banner;